/*
大概思路就是先对时间进行离散化，
然后根据离散化后的时间设计 DP 状态，
dp[i][j] 表示消灭出现在时间（离散化后的）i 到 j 的外星人所需的最小成本。
然后注意到肯定一个区间只消灭一次外星人，
故可以找到这个时间范围中距离人最远的外星人然后只考虑他，
对应的就可以推出状态转移方程了。
*/
#include<bits/stdc++.h>
using namespace std;
const int N = 605 , K = 1e4+5;
struct node{int l,r,d;}a[N];
int T,n,tmp[N],cnt,dui[K],dp[N][N];
int main(){
    cin>>T;
    while(T--){
        cin>>n;cnt=0;
        for(int i=1;i<=n;i++){
            cin>>a[i].l>>a[i].r>>a[i].d;
            tmp[++cnt]=a[i].l,tmp[++cnt]=a[i].r;
            //存储所有出现过的时间，后面要用来离散化
        }
        sort(tmp+1,tmp+cnt+1);//排序
        for(int i=1;i<=cnt;i++)dui[tmp[i]]=i;//映射离散化
        for(int i=1;i<=n;i++)
            a[i].l=dui[a[i].l],a[i].r=dui[a[i].r];//在数组上实施离散化
        for(int len=2;len<=cnt;len++){
            //普通区间 DP，枚举区间长度
            for(int i=1;i+len-1<=cnt;i++){//枚举区间起点
                int j=i+len-1,mx=0;
                //通过长度和起点计算终点
                //mx 记录这个时间区间中距离最远的外星人
                dp[i][j]=0x3f3f3f3f;
                //初始化为极大值（也可以在外面初始化）
                for(int k=1;k<=n;k++){//枚举所有外星人找最远
                    if(a[k].l<i||a[k].r>j)continue;
                    //如果这个外星人没被完整包含在这个时间区间中就跳过
                    if(!mx||a[k].d>a[mx].d)mx=k;//对应更行 mx 值
                }
                if(!mx){dp[i][j]=0;continue;}
                //如果没有外星人，让 DP 值为 0 并跳过
                for(int k=a[mx].l;k<=a[mx].r;k++)
                    dp[i][j]=min(dp[i][j],dp[i][k-1]+dp[k+1][j]+a[mx].d);
                //转移，枚举消灭最远外星人的时间，对应进行转移
                //注意转移时 k 时刻是不能包含在区间中的
                //计算时要额外加上消灭最远外星人所耗费的成本
            }
        }
        cout<<dp[1][cnt]<<"\n";//最后输出即可
    }
    return 0;
}
